const columns = [
  {
    dataIndex: 'name',
    key: 'name',
    title: '部门名称',
    slots: { customRender: 'name' },
  },

  {
    title: '所属上级',
    dataIndex: 'parentName',
    key: 'parentName',
  },
  {
    title: '部门编号',
    dataIndex: 'code',
    key: 'code',
  },
  {
    title: '部门职责',
    dataIndex: 'duty',
    key: 'duty',
  },

  {
    title: '操作',
    key: 'action',
    slots: { customRender: 'action' },
  },
];
import { deptdel, } from '@/server/http/api/role'
import { inject, ref } from 'vue';

export function Department(props: any, ctx: any) {
  let init: any = inject('initDepartment')

  function del(id: number) {
    // 删除部门
    deptdel(id).then((res: any) => {
      if (res.data.code === 200) {
        init()
      }
    })

  }
  return {
    columns,

    del
  }
}