
import { ref, defineComponent, reactive, inject } from "vue";
import TreeNode from "@/components/tree/TreeNode.vue";
import { deptedit } from "@/server/http/api/role";
export default defineComponent({
  components: { TreeNode },
  props: ["detail"],
  setup(props) {
    const formRef = ref();

    const rules = {};
    let init: any = inject("initDepartment");

    const formState: any = reactive({
      id: "",
      name: "",
      parentId: "",
      code: "",
      duty: "",
    });
    let dev = ref("");

    function onDepartmentID(options: any) {
      formState.parentId = options.id;
      dev.value = options.name;
    }

    const visible = ref<boolean>(false);
    const confirmLoading = ref<boolean>(false);

    const showModal = () => {
      let { name, id, parentId, duty, code } = props.detail;
      formState.name = name;
      formState.parentId = parentId;
      formState.code = code;
      formState.duty = duty;
      formState.id = id;
      visible.value = true;
    };

    const handleOk = () => {
      formRef.value
        .validate()
        .then(() => {
          confirmLoading.value = true;
          deptedit(formState).then((res: any) => {
            visible.value = false;
            confirmLoading.value = false;
            // 删除后重新
            init();
          });
        })
        .catch((error: any) => {
          //console.log("error", error);
        });
    };
    return {
      visible,
      confirmLoading,
      showModal,
      handleOk,
      formState,
      onDepartmentID,
      labelCol: { span: 4 },
      wrapperCol: { span: 20 },
      dev,
      rules,
      formRef,
    };
  },
});
