
import { SmileOutlined, DownOutlined } from "@ant-design/icons-vue";
import { defineComponent } from "vue";
import { Department } from "./Department";
import { Personnel } from "./Personnel";
import UpdateDepartment from "./modalRole/UpdateDepartment.vue";
import UpdatePreson from "./modalRole/UpdatePreson.vue";

export default defineComponent({
  props: ["typeName", "list"],
  emits: ["hasSelected"],
  components: {
    UpdateDepartment,
    UpdatePreson,
    SmileOutlined,
    DownOutlined,
  },
  setup(props, ctx) {
    if (props.typeName === "人员管理") {
      const department = Personnel(props, ctx);

      return {
        ...department,
      };
    }
    if (props.typeName === "部门管理") {
      const Personnel = Department(props, ctx);
      return {
        ...Personnel,
      };
    }
  },
});
