// 人员添加
interface AddPerson {
    name: string
    position: string
    department: string
    email: string
    mobile: string
    orgemail: string
    jobnumber: string
}
export function addPerson(options: AddPerson) {

    return http.post('/jkyErp/dept/person_add', options)
}


// 人员编辑
interface editPerson {
    name: string
    position: string
    department: string
    userid: string
    email: string
    mobile: string
    orgemail: string
    jobnumber: string
}
export function editPerson(options: editPerson) {
    return http.post('/jkyErp/dept/person_edit', options)
}


// 人员删除

export function delPerson(ids: any) {
    return http.post('/jkyErp/dept/person_delete', { ids })
}

// 人员列表
interface PersonList {
    search?: string
    pageNum: number
    pageSize: number
    id: number,
    isInclude: string
}
export function PersonList(options: PersonList) {
    return http.get('/jkyErp/dept/personList', options)
}

interface Deptlist {
    pageNum: number
    pageSize: number,
    search?: string
}
// 部门列表
export function deptlist(options: Deptlist) {
    return http.get('/jkyErp/dept/list', options)
}

// 部门树
export function deptsonList(id?: number) {
    return http.get('/jkyErp/dept/sonList', { id })
}

// 部门新增
interface Deptadd {
    name: string
    parentId: string
}
export function deptadd(options: Deptadd) {
    return http.post('/jkyErp/dept/add', options)
}

// 部门修改

interface Deptedit {
    name: string
    parentId: string
    id: number
}
export function deptedit(options: Deptedit) {
    return http.post('/jkyErp/dept/edit', options)
}

// 部门删除
export function deptdel(id: number) {
    return http.get('/jkyErp/dept/delete', { id })
} 
