
import { defineComponent, onMounted, ref, watch } from "vue";
import { deptsonList } from "@/server/http/api/role";
import { toTree } from "@/utils/toTree";

export default defineComponent({
  emits: ["onDepartmentID"],
  props: {
    ids: {
      default: [],
    },
    clearFlag: {
      default: true,
    },
  },
  setup(props, { emit }) {
    let dataTree = ref([]);
    const expandedKeys = ref<string[]>([]);
    const selectedKeys = ref<string[]>([]);

    let data: any = ref([]);
    deptsonList().then((res: any) => {
      if (res.data.code === 200) {
        //console.log(res.data.data);

        data.value = res.data.data;
        selectedKeys.value = props.ids;
        dataTree.value = toTree(res.data.data);
      }
    });

    watch(selectedKeys, (newVal) => {
      let obj = data.value.find((item: any) => {
        return item.id === newVal[0];
      });
      if (obj !== undefined) {
        emit("onDepartmentID", { id: newVal[0], name: obj.name });
      } else {
        emit("onDepartmentID", { id: "", name: "" });
      }
    });

    function clear() {
      selectedKeys.value = [];
      expandedKeys.value = [];
    }
    return {
      expandedKeys,
      selectedKeys,
      // treeData,
      dataTree,
      clear,
    };
  },
});
