import { computed, inject, onMounted, onUnmounted, reactive, ref, toRefs, watch } from "vue";
import bus from '@/utils/bus'
const columns = [
    {
        title: '姓名',
        dataIndex: 'name',
        key: 'name',
        slots: { customRender: 'name' },

    },
    {
        title: '工号',
        dataIndex: 'jobnumber',
        key: 'jobnumber',
        slots: { customRender: 'jobnumber' },

    },
    {
        title: '手机号',
        dataIndex: 'mobile',
        key: 'mobile',
        slots: { customRender: 'mobile' },

    },
    {
        title: '邮箱',
        dataIndex: 'orgemail',
        key: 'orgemail',
        slots: { customRender: 'orgemail' },

    },
    {
        title: '部门',
        dataIndex: 'workplace',
        key: 'workplace',
    },
    {
        title: '职位',
        dataIndex: 'position',
        key: 'position',
    },
    {
        title: '操作',
        key: 'action',
        slots: { customRender: 'action' },
    },
];

import { delPerson, deptsonList } from '@/server/http/api/role'
export function Personnel(props: any, { emit }: any) {

    let initPersonList: any = inject("initPersonList");

    const state = reactive({
        selectedRowKeys: [], // Check here to configure the default column
    });
    const hasSelected = computed(() => state.selectedRowKeys.length > 0);

    const onSelectChange = (selectedRowKeys: []) => {
        //console.log('selectedRowKeys changed: ', selectedRowKeys);
        state.selectedRowKeys = selectedRowKeys;
        emit('hasSelected', {
            selectedRowKeys: state.selectedRowKeys,
            hasSelected: hasSelected
        })
    };
    onMounted(() => {
        bus.on('delPresonlist', () => {
            state.selectedRowKeys = []
        })
    })


    onUnmounted(() => {
        bus.off('delPresonlist')
    })
    function del(id: any) {
        delPerson([id]).then((res: any) => {
            initPersonList()
        })
    }


    let DepartmentList: any = ref([])
    deptsonList().then((res: any) => {
        if (res.data.code === 200) {
            res.data.data.map((item: any) => {
                DepartmentList.value.push({ label: item.name, value: item.id + '' })
            })
        }
        // //console.log(DepartmentList.value);

    })
    return {
        columns,

        del,
        ...toRefs(state),
        onSelectChange,
        hasSelected,
        DepartmentList

    }
}